// C: static void f_luaopen(lua_State *L, void *ud)
fn lua_open(state: &mut LuaState) -> Result<(), LuaError> {
    // C: UNUSED(ud);
    // C: stack_init(L, L);
    stack_init(state);
    // C: init_registry(L, g);
    init_registry(state)?;
    // C: luaS_init(L);
    crate::string::init(state)?;
    // C: luaT_init(L);
    // TODO(port): crate::tagmethods::init(state)? — ltm.c → tagmethods.rs, not yet written
    // C: luaX_init(L);
